def test_tc_vs_013_correct_can_id(can_bus):
    simulate_vehicle_speed(can_bus, 40)
    end_time = time.time() + 1.0
    while time.time() < end_time:
        msg = can_bus.recv(timeout=0.1)
        if msg and decode_vehicle_speed(msg.data) > 0:
            assert msg.arbitration_id == 0x200
